document.addEventListener("DOMContentLoaded", () => {
setupMobileMenu();
setupTheme();
setupLanguage();
setupHeroSlider();
setupCourseSwitcher();
setupCardTiltEffects();
setupBrandScroller();
setupReviewsScroller();
});
function setupMobileMenu() {
const hamburger = document.getElementById("hamburger");
const navMenu = document.getElementById("navMenu");
const navLinks = document.querySelectorAll(".nav-link");
if (hamburger && navMenu) {
hamburger.addEventListener("click", () => {
hamburger.classList.toggle("open");
navMenu.classList.toggle("open");
});
navLinks.forEach(link => {
link.addEventListener("click", () => {
hamburger.classList.remove("open");
navMenu.classList.remove("open");
});
});
}
}
function setupTheme() {
const themeToggleBtn = document.getElementById("themeToggle");
const currentTheme = localStorage.getItem("theme");
if (currentTheme === "light") {
document.body.classList.add("light-mode");
}
if (themeToggleBtn) {
themeToggleBtn.addEventListener("click", () => {
document.body.classList.toggle("light-mode");
let theme = "dark";
if (document.body.classList.contains("light-mode")) {
theme = "light";
}
localStorage.setItem("theme", theme);
});
}
}
function setupLanguage() {
const langSelect = document.getElementById("langSelect");
let currentLang = localStorage.getItem("language") || "tr";
langSelect.value = currentLang;
updatePageLanguage(currentLang);
if (langSelect) {
langSelect.addEventListener("change", (e) => {
const selectedLang = e.target.value;
localStorage.setItem("language", selectedLang);
updatePageLanguage(selectedLang);
document.documentElement.lang = selectedLang;
});
}
}
function updatePageLanguage(lang) {
const translatableElements = document.querySelectorAll("[data-i18n]");
translatableElements.forEach(element => {
const key = element.getAttribute("data-i18n");
if (translations[key] && translations[key][lang]) {
const text = translations[key][lang];
if (text.includes("<span")) {
element.innerHTML = text;
} else {
element.textContent = text;
}
}
});
const tooltipElements = document.querySelectorAll("[data-i18n-tooltip]");
tooltipElements.forEach(element => {
const key = element.getAttribute("data-i18n-tooltip");
if (translations[key] && translations[key][lang]) {
element.setAttribute("data-tooltip", translations[key][lang]);
}
});
}
function setupHeroSlider() {
const slides = document.querySelectorAll(".hero-slide");
const dots = document.querySelectorAll(".slider-dot");
const prevBtn = document.getElementById("sliderPrev");
const nextBtn = document.getElementById("sliderNext");
const sliderContainer = document.getElementById("heroSlider");
if (slides.length === 0) return;
let currentSlide = 0;
let slideInterval;
const intervalTime = 4000;
const goToSlide = (n) => {
slides[currentSlide].classList.remove("active");
dots[currentSlide].classList.remove("active");
currentSlide = (n + slides.length) % slides.length;
slides[currentSlide].classList.add("active");
dots[currentSlide].classList.add("active");
};
const nextSlide = () => {
goToSlide(currentSlide + 1);
};
const prevSlide = () => {
goToSlide(currentSlide - 1);
};
const startSlideShow = () => {
clearInterval(slideInterval);
slideInterval = setInterval(nextSlide, intervalTime);
};
const resetSlideShow = () => {
clearInterval(slideInterval);
startSlideShow();
};
if (nextBtn) {
nextBtn.addEventListener("click", () => {
nextSlide();
resetSlideShow();
});
}
if (prevBtn) {
prevBtn.addEventListener("click", () => {
prevSlide();
resetSlideShow();
});
}
dots.forEach((dot, index) => {
dot.addEventListener("click", () => {
goToSlide(index);
resetSlideShow();
});
});
if (sliderContainer) {
sliderContainer.addEventListener("mouseenter", () => {
clearInterval(slideInterval);
});
sliderContainer.addEventListener("mouseleave", startSlideShow);
}
startSlideShow();
}
function setupCourseSwitcher() {
const pageFoldBtn = document.getElementById("pageFoldBtn");
const paperContainer = document.getElementById("paperContainer");
const panelPilotaj = document.getElementById("panelPilotaj");
const panelDrone = document.getElementById("panelDrone");
const pageFoldBadge = document.getElementById("pageFoldBadge");
if (!pageFoldBtn || !paperContainer || !panelPilotaj || !panelDrone || !pageFoldBadge) return;
let currentCategory = "drone";
let isAnimating = false;
function toggleCategory() {
if (isAnimating) return;
isAnimating = true;
const rect = paperContainer.getBoundingClientRect();
paperContainer.style.setProperty("--container-w", `${rect.width}px`);
paperContainer.style.setProperty("--container-h", `${rect.height}px`);
paperContainer.classList.add("turning-page");
setTimeout(() => {
const currentLang = document.getElementById("langSelect")?.value || "tr";
if (currentCategory === "pilotaj") {
currentCategory = "drone";
panelPilotaj.classList.remove("active");
panelDrone.classList.add("active");
pageFoldBadge.setAttribute("data-i18n", "badge_switch_to_pilotaj");
if (translations["badge_switch_to_pilotaj"] && translations["badge_switch_to_pilotaj"][currentLang]) {
pageFoldBadge.textContent = translations["badge_switch_to_pilotaj"][currentLang];
}
} else {
currentCategory = "pilotaj";
panelDrone.classList.remove("active");
panelPilotaj.classList.add("active");
pageFoldBadge.setAttribute("data-i18n", "badge_switch_to_drone");
if (translations["badge_switch_to_drone"] && translations["badge_switch_to_drone"][currentLang]) {
pageFoldBadge.textContent = translations["badge_switch_to_drone"][currentLang];
}
}
}, 500);
setTimeout(() => {
paperContainer.classList.remove("turning-page");
isAnimating = false;
}, 1000);
}
pageFoldBtn.addEventListener("click", toggleCategory);
}
function setupCardTiltEffects() {
const cards = document.querySelectorAll(".course-card");
cards.forEach(card => {
card.addEventListener("mousemove", (e) => {
const cardRect = card.getBoundingClientRect();
const cardWidth = cardRect.width;
const cardHeight = cardRect.height;
const mouseX = e.clientX - cardRect.left - cardWidth / 2;
const mouseY = e.clientY - cardRect.top - cardHeight / 2;
const rotateX = -(mouseY / (cardHeight / 2)) * 8;
const rotateY = (mouseX / (cardWidth / 2)) * 8;
card.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) translateY(-8px) scale(1.02)`;
});
card.addEventListener("mouseleave", () => {
card.style.transform = "";
});
});
}
function setupBrandScroller() {
const slider = document.getElementById("brandsSlider");
if (!slider) return;
const originalLogos = Array.from(slider.children);
const count = originalLogos.length;
if (count === 0) return;
const logoWidth = 120;
const gap = 80;
const scrollWidth = count * (logoWidth + gap);
slider.style.setProperty("--scroll-width", `-${scrollWidth}px`);
for (let i = 0; i < 3; i++) {
originalLogos.forEach(logo => {
const clone = logo.cloneNode(true);
clone.setAttribute("aria-hidden", "true");
slider.appendChild(clone);
});
}
}
function setupReviewsScroller() {
const slider = document.getElementById("reviewsSlider");
if (!slider) return;
const originalCards = Array.from(slider.children);
const count = originalCards.length;
if (count === 0) return;
const cardWidth = 360;
const gap = 30;
const scrollWidth = count * (cardWidth + gap);
slider.style.setProperty("--scroll-width-reviews", `-${scrollWidth}px`);
for (let i = 0; i < 3; i++) {
originalCards.forEach(card => {
const clone = card.cloneNode(true);
clone.setAttribute("aria-hidden", "true");
slider.appendChild(clone);
});
}
}